func TestIsOpenAt_MidnightClose(t *testing.T) {
	at, err := parseHM("23:30")
	if err != nil {
		t.Fatalf("parse time: %v", err)
	}
	hours := []rappi.OpeningHoursSpec{{
		DayOfWeek: "Sunday",
		Opens:     "12:00:00",
		Closes:    "00:00:00",
	}}
	open, matched := isOpenAt(hours, "sunday", at)
	if !open {
		t.Fatalf("expected open until midnight, got closed (%q)", matched)
	}
}

func TestIsOpenAt_CrossMidnightWindow(t *testing.T) {
	hours := []rappi.OpeningHoursSpec{{
		DayOfWeek: "Sunday",
		Opens:     "22:00",
		Closes:    "02:00",
	}}
	for _, raw := range []string{"22:00", "23:30"} {
		at, err := parseHM(raw)
		if err != nil {
			t.Fatalf("parse %s: %v", raw, err)
		}
		open, _ := isOpenAt(hours, "sunday", at)
		if !open {
			t.Fatalf("expected %s sunday to match sunday 22:00-02:00", raw)
		}
	}

	at, err := parseHM("01:30")
	if err != nil {
		t.Fatalf("parse time: %v", err)
	}
	open, _ := isOpenAt(hours, "monday", at)
	if !open {
		t.Fatal("expected monday 01:30 to match sunday 22:00-02:00")
	}

	at, err = parseHM("02:00")
	if err != nil {
		t.Fatalf("parse time: %v", err)
	}
	open, _ = isOpenAt(hours, "monday", at)
	if open {
		t.Fatal("expected closing instant to be treated as closed")
	}
}
